const fs = require('fs');
const path = require('path');

const FILE = path.join(__dirname, 'index.html');
if (!fs.existsSync(FILE)) { console.error('Not found: index.html'); process.exit(1); }

let html = fs.readFileSync(FILE, 'utf8');

// Replace the gen-card-visual div with an embedded video
const old = '<div class="gen-card-visual"></div>';
const newHtml = `<div class="gen-card-visual" style="padding:0;overflow:hidden;position:relative">
  <video autoplay muted loop playsinline style="position:absolute;inset:0;width:100%;height:100%;object-fit:cover;border-radius:0 12px 12px 0;opacity:.85" src="data:video/mp4;base64,"></video>
</div>`;

if (html.includes(old)) {
  html = html.replace(old, newHtml);
  fs.writeFileSync(FILE, html, 'utf8');
  console.log('Done! Gen card video embedded.');
} else {
  console.error('Could not find gen-card-visual div. Has the HTML changed?');
}
